import java.io.FileWriter;
import java.io.IOException;
import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input from a form submission
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize user input to prevent XSS attacks
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);
        String sanitizedInput = policy.sanitize(userInput);

        // Displaying sanitized user input on a web page
        try (FileWriter writer = new FileWriter("output.html")) {
            writer.write("<html>");
            writer.write("<body>");
            writer.write("<h1>User Input: " + sanitizedInput + "</h1>");
            writer.write("</body>");
            writer.write("</html>");
        }
    }
}

